function solve(postfix) {
  if (typeof postfix !== 'string') return 'Error: Invalid input';
  const tokens = postfix.trim().split(/\s+/).filter(t => t.length > 0);
  const stack = [];
  for (const t of tokens) {
    if (!isNaN(Number(t))) {
      stack.push(Number(t));
    } else if (['+','-','*','/'].includes(t)) {
      if (stack.length < 2) return 'Error: Insufficient operands';
      const b = stack.pop();
      const a = stack.pop();
      let res;
      if (t === '+') res = a + b;
      else if (t === '-') res = a - b;
      else if (t === '*') res = a * b;
      else {
        if (b === 0) return 'Error: Division by zero';
        res = a / b;
      }
      stack.push(res);
    } else {
      return 'Error: Invalid token';
    }
  }
  if (stack.length !== 1) return 'Error: Invalid expression';
  return stack[0];
}

