def solve(postfix):
  if not isinstance(postfix, str):
    return 'Error: Invalid input'
  tokens = [t for t in postfix.strip().split() if t]
  stack = []
  for t in tokens:
    if t.replace('.', '', 1).lstrip('-').isdigit():
      stack.append(float(t) if '.' in t else int(t))
    elif t in ('+','-','*','/'):
      if len(stack) < 2:
        return 'Error: Insufficient operands'
      b = stack.pop()
      a = stack.pop()
      if t == '+': res = a + b
      elif t == '-': res = a - b
      elif t == '*': res = a * b
      else:
        if b == 0:
          return 'Error: Division by zero'
        res = a / b
      stack.append(res)
    else:
      return 'Error: Invalid token'
  if len(stack) != 1:
    return 'Error: Invalid expression'
  return stack[0]

