def solve(param):
    nums = param.get('nums', [])
    k = param.get('k', 0)
    arr = sorted(nums)
    i, j = 0, len(arr) - 1
    max_sum = 0
    while i < j:
        if arr[j] - arr[i] <= k:
            max_sum = max(max_sum, arr[i] + arr[j])
            i += 1
        else:
            j -= 1
    return max_sum
